{
  "name": "SHINE (Serving Health Insurance Needs of Elders)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits for SHINE counseling itself; open to all Medicare beneficiaries, families, and caregivers. SHINE assists with programs like Extra Help (monthly income below $1,995 single; resources below $18,090) and Medicare Savings Programs (limits vary, apply even if slightly higher).[8]",
    "asset_limits": "No asset limits for SHINE access. For assisted programs like Extra Help, resources below $18,090 (excludes home, car, etc.; consult SHINE for details).[8]",
    "other_requirements": ["Medicare beneficiary or prospective beneficiary (Parts A/B enrollment for some assisted benefits)", "Florida resident", "No affiliation requirement; services free to all regardless of income/age"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, unbiased, confidential one-on-one counseling on Medicare eligibility/enrollment, health plan choices, appeals, Medigap, long-term care insurance, prescription assistance, fraud prevention, and financial aid programs like Extra Help/Medicare Savings Programs. Educational presentations and community outreach also available.[3][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free Elder Helpline 1-800-963-5337 (8am-5pm)", "Website: www.floridashine.org (find counseling sites, online volunteer app, orientation)", "In-person: Local Area Agency on Aging SHINE sites (locate via website)", "Online training/orientation: http://training.floridashine.org/STL_Modules/Orientation/story.html (for volunteers)"],
    "processing_time": "Immediate counseling availability via phone/sites; no formal processing for service access",
    "waitlist": null,
    "forms": ["No specific client application form; consultation-based. Volunteer application online or via phone"],
    "documents": ["Medicare card, income/resource details for assisted program applications (e.g., Extra Help), insurance documents for review"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Florida only",
    "regional_variations": "Delivered through 11 local Area Agencies on Aging; volunteer networks, counseling sites, and events vary by region (e.g., Senior Connection Center in Tampa serves specific counties; SWFL AAA serves southwest).[4][6][7]",
    "offices_or_providers": ["Florida Department of Elder Affairs, 4040 Esplanade Way, Suite 280-S, Tallahassee, FL 32399", "Local Area Agencies on Aging (find via www.floridashine.org)"]
  },
  "official_source": "www.floridashine.org",
  "gotchas": ["SHINE does not provide direct financial aid or healthcare; it counsels on accessing Medicare-related benefits. Not affiliated with insurers—volunteers neither sell nor recommend specific plans.", "Many eligible for savings programs (e.g., 35,000+ in some areas) remain unenrolled; must consult SHINE for application help.", "Virtual/in-person events vary; check site for availability.", "Assists with Extra Help/MSP but eligibility screened separately (e.g., DEERS for TRICARE)."],
  "data_shape_notes": "Counseling program with no client eligibility barriers; assists applying to tiered financial aid programs with income/resource tests; volunteer-driven via regional Area Agencies on Aging"
}
